 15→const assistantReplySchema = z.object({
 16→  message: z.string().min(1),
 17→  suggestions: z.array(z.string().min(1)).max(3),
 18→});
 19→
 20→export async function generateOnboardingAssistantReply(input: {
 21→  chatAgentModel: any;
 22→  surreal: Surreal;
 23→  onboardingState: OnboardingState;
 24→  contextRows: MessageContextRow[];
 25→  latestUserText: string;
 26→  workspaceRecord: RecordId<"workspace", string>;
 27→  workspaceDescription?: string;
 28→  latestEntities: Array<{ kind: EntityKind; text: string; confidence: number }>;
 29→  latestTools: string[];
 30→}): Promise<{ message: string; suggestions: string[] }> {
 31→  const suggestionAnchors = buildSuggestionAnchors(input.latestUserText, input.latestEntities, input.latestTools);
 32→  const suggestionQualityRules = [
 33→    "You are helping a product team capture actionable project state.",
 34→    "Suggestion quality rules:",
 35→    "- Suggestions are 0-3 short clickable strings.",
 36→    "- Mandatory algorithm:",
 37→    "  1) Build candidate anchors by copying exact phrases from latest user message or latest extraction context.",
 38→    "  2) Prefer concrete anchors: person names, tool names, feature/task phrases (for example SurrealDB, GitHub commit awareness, Slack ingestion, schemafull constraints, onboarding prompts).",
 39→    "  3) Use only anchors from the provided 'Allowed suggestion anchors' list.",
 40→    "  4) If the allowed anchor list is empty, return suggestions: [].",
 41→    "  5) Every suggestion must include at least one allowed anchor phrase verbatim.",
 42→    "  6) Suggestions must ask about next-step details (risk, sequencing, ownership, scope, dependency, rollout, validation) for that anchor.",
 43→    "  7) Never ask for unrelated generic onboarding info (team/business/project overviews) unless that exact wording exists in allowed anchors.",
 44→    "- Never output generic suggestions detached from latest context.",
 45→    "- Forbidden generic suggestions or equivalents:",
 46→    "  - Describe current projects",
 47→    "  - Describe your current project",
 48→    "  - List key team members",
 49→    "  - Identify biggest bottleneck",
 50→    "  - Tell me about your business",
 51→    "  - Tell me about the overall project",
 52→    "  - Describe the business for these tasks",
 53→    "  - Explain the context of these tasks",
 54→    "- Low-signal turn rule: if latest user message is only filler/acknowledgment (for example 'ok', 'sounds good', 'ok and to be'), return suggestions: [].",
 55→    "- Example input: Marcus is driving extraction, Dana is reviewing schemafull constraints, and we're refining onboarding prompts.",
 56→    "- Good suggestions: What risk should Dana prioritize in schemafull constraints? | What is the next milestone for onboarding prompts? | What dependency is blocking extraction work for Marcus?",
 57→    "- Bad suggestions: Tell me about the overall project | Describe the business for these tasks",
 58→    "- Example input: We're building ... with SurrealDB, cross-project conflict detection, GitHub commit awareness, and Slack ingestion.",
 59→    "- Good suggestions: Which risk is highest for SurrealDB this week? | Should GitHub commit awareness ship before Slack ingestion? | What test validates cross-project conflict detection?",
 60→    "- Example input: ok and to be",
 61→    "- Good suggestions: []",
 62→  ].join("\n");
 63→
 64→  let systemPrompt = [
 65→    suggestionQualityRules,
 66→    "",
 67→    "Respond concisely with clear next actions.",
 68→  ].join("\n");
 69→
 70→  if (input.onboardingState === "active") {
 71→    const summary = await loadOnboardingSummary(input.surreal, input.workspaceRecord);
 72→    const topicList = input.workspaceDescription
 73→      ? "projects and product areas, people involved, most important decision, tools used, biggest bottleneck."
 74→      : "business/venture, current projects, people involved, most important decision, tools used, biggest bottleneck.";
 75→    systemPrompt = [
 76→      suggestionQualityRules,
 77→      "",
 78→      "You are onboarding a newly created workspace.",
 79→      ...(input.workspaceDescription
 80→        ? [`The workspace is already described as: "${input.workspaceDescription}"`, "Do not ask what the business or workspace is about — focus on discovering projects and product areas within it."]
 81→        : []),
 82→      "Ask one natural question at a time like a smart colleague, never as a form.",
 83→      `Cover these topics over 5-7 turns: ${topicList}`,
 84→      "Keep acknowledgment to one sentence max.",
 85→      "Ask exactly one concrete follow-up question in every response.",
 86→      "Confirm captured entities inline in plain language.",
 87→      "Generate up to 3 short clickable follow-up suggestions.",
 88→      "Apply the Suggestion quality rules exactly.",
 89→      "Do not use generic onboarding-checklist suggestions.",
 90→      "Current extracted context:",
 91→      summary,
 92→    ].join("\n");
 93→  }
 94→
 95→  if (input.onboardingState === "summary_pending") {
 96→    const summary = await loadOnboardingSummary(input.surreal, input.workspaceRecord);
 97→    systemPrompt = [
 98→      suggestionQualityRules,
 99→      "",
100→      "You are finishing onboarding for a workspace.",
101→      "Summarize what has been captured in a concise bullet list.",
102→      "Ask the user to choose one of two explicit actions:",
103→      "- Looks good, let's go",
104→      "- I want to add more",
105→      "Generate up to 3 short clickable follow-up suggestions.",
106→      "Apply the Suggestion quality rules exactly.",
107→      "Do not use generic onboarding-checklist suggestions.",
108→      "Current extracted context:",
109→      summary,
110→    ].join("\n");
111→  }
112→
113→  const assistantResponse = await generateObject({
114→    model: input.chatAgentModel,
115→    schema: assistantReplySchema,
116→    system: systemPrompt,
117→    prompt: [
118→      "Return JSON with this shape: { message: string, suggestions: string[] }.",
119→      "Message may include markdown and ```component fenced JSON when useful.",
120→      "Suggestions must be short and actionable, plain strings only.",
121→      "When in doubt, prefer suggestions: [] over generic suggestions.",
122→      "Conversation context:",
123→      formatContextRows(input.contextRows),
124→      "",
125→      "Allowed suggestion anchors (suggestions must include at least one verbatim):",
126→      formatSuggestionAnchors(suggestionAnchors),
127→      "",
128→      "Latest extraction context:",
129→      formatLatestExtractionContext(input.latestEntities, input.latestTools),
130→      "",
131→      "Latest user message:",
132→      input.latestUserText,
133→    ].join("\n"),
